 \\ 
 \mathsf {add} { \mathopen {} \left ( m,0 \right ) \mathclose {}}  &= m
 \\ 
 \mathsf {add} { \mathopen {} \left ( m,n+1 \right ) \mathclose {}}  &=  \mathsf {add} { \mathopen {} \left ( m,n \right ) \mathclose {}} +1
